16	const GLchar* const textvertexshader_source = ""
17	"#version 330\n"
18	"layout (location = 0) in vec4 position;\n"
19	"out vec2 texCoords;\n"
20	"void main()\n"
21	"{\n"
22	    "gl_Position = vec4(position.xy, 0, 1);\n"
23	    "texCoords = position.zw;\n"
24	"}\n"
