38	void TextRendering_LoadShader(const GLchar* const shader_string, GLuint shader_id)
39	{
40	    // Define o código do shader, contido na string "shader_string"
41	    glShaderSource(shader_id, 1, &shader_string, NULL);
42	
43	    // Compila o código do shader (em tempo de execução)
44	    glCompileShader(shader_id);
45	
46	    // Verificamos se ocorreu algum erro ou "warning" durante a compilação
47	    GLint compiled_ok;
48	    glGetShaderiv(shader_id, GL_COMPILE_STATUS, &compiled_ok);
49	
50	    GLint log_length = 0;
51	    glGetShaderiv(shader_id, GL_INFO_LOG_LENGTH, &log_length);
52	
53	    // Alocamos memória para guardar o log de compilação.
54	    // A chamada "new" em C++ é equivalente ao "malloc()" do C.
55	    GLchar* log = new GLchar[log_length];
56	    glGetShaderInfoLog(shader_id, log_length, &log_length, log);
57	
58	    // Imprime no terminal qualquer erro ou "warning" de compilação
59	    if ( log_length != 0 )
60	    {
61	        std::string  output;
62	
63	        if ( !compiled_ok )
64	        {
65	            output += "ERROR: OpenGL compilation failed.\n";
66	            output += "== Start of compilation log\n";
67	            output += log;
68	            output += "== End of compilation log\n";
69	        }
70	        else
71	        {
72	            output += "ERROR: OpenGL compilation failed.\n";
73	            output += "== Start of compilation log\n";
74	            output += log;
75	            output += "== End of compilation log\n";
76	        }
77	
78	        fprintf(stderr, "%s", output.c_str());
79	    }
80	
81	    // A chamada "delete" em C++ é equivalente ao "free()" do C
82	    delete [] log;
83	}
