90	void TextRendering_Init()
91	{
92	    GLuint sampler;
93	
94	    glGenBuffers(1, &textVBO);
95	    glGenVertexArrays(1, &textVAO);
96	    glGenTextures(1, &texttexture_id);
97	    glGenSamplers(1, &sampler);
98	    glSamplerParameteri(sampler, GL_TEXTURE_WRAP_S, GL_CLAMP_TO_EDGE);
99	    glSamplerParameteri(sampler, GL_TEXTURE_WRAP_T, GL_CLAMP_TO_EDGE);
100	    glSamplerParameteri(sampler, GL_TEXTURE_MIN_FILTER, GL_LINEAR);
101	    glSamplerParameteri(sampler, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
102	    glCheckError();
103	
104	    GLuint textvertexshader_id = glCreateShader(GL_VERTEX_SHADER);
105	    TextRendering_LoadShader(textvertexshader_source, textvertexshader_id);
106	    glCheckError();
107	
108	    GLuint textfragmentshader_id = glCreateShader(GL_FRAGMENT_SHADER);
109	    TextRendering_LoadShader(textfragmentshader_source, textfragmentshader_id);
110	    glCheckError();
111	
112	    textprogram_id = CreateGpuProgram(textvertexshader_id, textfragmentshader_id);
113	    glLinkProgram(textprogram_id);
114	    glCheckError();
115	
116	    GLuint texttex_uniform;
117	    texttex_uniform = glGetUniformLocation(textprogram_id, "tex");
118	    glCheckError();
119	
120	    GLuint textureunit = 31;
121	    glActiveTexture(GL_TEXTURE0 + textureunit);
122	    glBindTexture(GL_TEXTURE_2D, texttexture_id);
123	    glTexImage2D(GL_TEXTURE_2D, 0, GL_R8, dejavufont.tex_width, dejavufont.tex_height, 0, GL_RED, GL_UNSIGNED_BYTE, dejavufont.tex_data);
124	    glBindSampler(textureunit, sampler);
125	    glCheckError();
126	
127	    glBindVertexArray(textVAO);
128	
129	    glBindBuffer(GL_ARRAY_BUFFER, textVBO);
130	    glBufferData(GL_ARRAY_BUFFER, 24 * sizeof(float), NULL, GL_DYNAMIC_DRAW);
131	    glVertexAttribPointer(0, 4, GL_FLOAT, GL_FALSE, 0, 0);
132	    glEnableVertexAttribArray(0);
133	    glCheckError();
134	
135	    glUseProgram(textprogram_id);
136	    glUniform1i(texttex_uniform, textureunit);
137	    glUseProgram(0);
138	    glCheckError();
139	
140	    glBindBuffer(GL_ARRAY_BUFFER, 0);
141	    glBindVertexArray(0);
142	    glCheckError();
143	}
