145	float textscale = 1.5f;
146	
147	void TextRendering_PrintString(GLFWwindow* window, const std::string &str, float x, float y, float scale = 1.0f)
148	{
149	    scale *= textscale;
150	    int width, height;
151	    glfwGetWindowSize(window, &width, &height);
152	    float sx = scale / width;
153	    float sy = scale / height;
154	
155	    for (size_t i = 0; i < str.size(); i++)
156	    {
157	        // Find the glyph for the character we are looking for
158	        texture_glyph_t *glyph = 0;
159	        for (size_t j = 0; j < dejavufont.glyphs_count; ++j)
160	        {
161	            if (dejavufont.glyphs[j].codepoint == (uint32_t)str[i])
162	            {
163	                glyph = &dejavufont.glyphs[j];
164	                break;
165	            }
166	        }
167	        if (!glyph) {
168	            continue;
169	        }
170	        x += glyph->kerning[0].kerning;
171	        float x0 = (float) (x + glyph->offset_x * sx);
172	        float y0 = (float) (y + glyph->offset_y * sy);
173	        float x1 = (float) (x0 + glyph->width * sx);
174	        float y1 = (float) (y0 - glyph->height * sy);
175	
176	        float s0 = glyph->s0 - 0.5f/dejavufont.tex_width;
177	        float t0 = glyph->t0 - 0.5f/dejavufont.tex_height;
178	        float s1 = glyph->s1 - 0.5f/dejavufont.tex_width;
179	        float t1 = glyph->t1 - 0.5f/dejavufont.tex_height;
180	
181	        struct {float x, y, s, t;} data[6] = {
182	            { x0, y0, s0, t0 },
183	            { x0, y1, s0, t1 },
184	            { x1, y1, s1, t1 },
185	            { x0, y0, s0, t0 },
186	            { x1, y1, s1, t1 },
187	            { x1, y0, s1, t0 }
188	        };
189	
190	        glEnable(GL_BLEND);
191	        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA);
192	
193	        glPolygonMode(GL_FRONT_AND_BACK, GL_FILL);
194	        glDepthFunc(GL_ALWAYS);
195	        glBindBuffer(GL_ARRAY_BUFFER, textVBO);
196	        glBufferSubData(GL_ARRAY_BUFFER, 0, 24 * sizeof(float), data);
197	        glBindBuffer(GL_ARRAY_BUFFER, 0);
198	
199	        glUseProgram(textprogram_id);
200	        glBindVertexArray(textVAO);
201	
202	        glDrawArrays(GL_TRIANGLES, 0, 6);
203	
204	        glBindVertexArray(0);
205	        glUseProgram(0);
206	        glDepthFunc(GL_LESS);
207	
208	        glDisable(GL_BLEND);
209	
210	        x += (glyph->advance_x * sx);
211	    }
212	}
