228	void TextRendering_PrintMatrix(GLFWwindow* window, glm::mat4 M, float x, float y, float scale = 1.0f)
229	{
230	    char buffer[40];
231	    float lineheight = TextRendering_LineHeight(window) * scale;
232	
233	    snprintf(buffer, 40, "[%+0.2f %+0.2f %+0.2f %+0.2f]", M[0][0], M[1][0], M[2][0], M[3][0]);
234	    TextRendering_PrintString(window, buffer, x, y, scale);
235	    snprintf(buffer, 40, "[%+0.2f %+0.2f %+0.2f %+0.2f]", M[0][1], M[1][1], M[2][1], M[3][1]);
236	    TextRendering_PrintString(window, buffer, x, y - lineheight, scale);
237	    snprintf(buffer, 40, "[%+0.2f %+0.2f %+0.2f %+0.2f]", M[0][2], M[1][2], M[2][2], M[3][2]);
238	    TextRendering_PrintString(window, buffer, x, y - 2*lineheight, scale);
239	    snprintf(buffer, 40, "[%+0.2f %+0.2f %+0.2f %+0.2f]", M[0][3], M[1][3], M[2][3], M[3][3]);
240	    TextRendering_PrintString(window, buffer, x, y - 3*lineheight, scale);
241	}
