243	void TextRendering_PrintVector(GLFWwindow* window, glm::vec4 v, float x, float y, float scale = 1.0f)
244	{
245	    char buffer[10];
246	    float lineheight = TextRendering_LineHeight(window) * scale;
247	
248	    snprintf(buffer, 10, "[%+0.2f]", v.x);
249	    TextRendering_PrintString(window, buffer, x, y, scale);
250	    snprintf(buffer, 10, "[%+0.2f]", v.y);
