252	    snprintf(buffer, 10, "[%+0.2f]", v.z);
253	    TextRendering_PrintString(window, buffer, x, y - 2*lineheight, scale);
254	    snprintf(buffer, 10, "[%+0.2f]", v.w);
255	    TextRendering_PrintString(window, buffer, x, y - 3*lineheight, scale);
256	}
