507	        emissive_color = Kd0 * 3.0;
508	    }
509	    else if ( object_id == RADIO_ANTENNA) 
510	    {
511	        U = texcoords.x;
512	        V = texcoords.y;
513	        Kd0 = texture(TextureImage27, vec2(U,V)).rgb;
514	        metalness = 1.0; // Força 100% metal
515	    }
516	    else if ( object_id == RADIO_BUTTON)
517	    {
518	        U = texcoords.x;
519	        V = texcoords.y;
520	        Kd0 = texture(TextureImage28, vec2(U,V)).rgb;
521	    }
522	    else if ( object_id == RADIO_BUTTON_RIFLED)
523	    {
524	        U = texcoords.x;
525	        V = texcoords.y;
526	        Kd0 = texture(TextureImage29, vec2(U,V)).rgb;
527	        metalness = 1.0; // Força 100% metal
528	    }
529	    else if ( object_id == RADIO_BASE_PART)
530	    {
531	        U = texcoords.x;
532	        V = texcoords.y;
533	        Kd0 = texture(TextureImage30, vec2(U,V)).rgb;
534	    }
535	    else if ( object_id == CAKE)
536	    {
537	        U = texcoords.x;
538	        V = texcoords.y;
539	        Kd0 = texture(TextureImage13, vec2(U,V)).rgb;
540	    }
541	    else if ( object_id == CAKE_CANDLE)
542	    {
543	        U = texcoords.x;
544	        V = texcoords.y;
545	        Kd0 = texture(TextureImage15, vec2(U,V)).rgb;
546	    }
547	    else if ( object_id == CAKE_CHERRY)
548	    {
549	        Kd0 = vec3(0.65, 0.05, 0.15);
550	    }
551	    else if ( object_id == CAKE_CHERRY_CREAM)
552	    {
553	        Kd0 = vec3(0.92, 0.90, 0.90);
554	    }
555	    else if ( object_id == CAKE_BOTTOM)
556	    {
557	        Kd0 = vec3(0.85, 0.40, 0.05);
558	    }
559	
560	
561	
562	
563	
564	
565	  // --- CÁLCULO DAS LUZES DO TETO ---
566	    vec3 total_diffuse = vec3(0.0);
567	    vec3 total_specular = vec3(0.0);
568	
569	    for(int i = 0; i < LIGHT_COUNT; i++) {
570	        // Vetor que aponta do fragmento para a luz atual
571	        vec3 light_dir = LIGHT_POSITIONS[i] - p.xyz;
572	        float dist = length(light_dir); // Distância até a luz
573	        vec3 l = normalize(light_dir);
574	
575	        // Atenuação: a luz perde força conforme chega no chão ou no meio da sala
576	        // Fraca/original, caso queiramos comparar:
577	        // float attenuation = 1.0 / (1.0 + 0.09 * dist + 0.04 * (dist * dist));
578	
579	        // Forte/nova: A luz perde força rapidamente, criando cantos escuros.
580	        float attenuation = 1.0 / (1.0 + 0.14 * dist + 0.07 * (dist * dist));
581	
582	        // Termo Difuso (Lambert)
583	        float lambert = max(0.0, dot(n.xyz, l));
584	        vec3 diffuse = Kd0 * LIGHT_COLORS[i] * lambert;
585	
586	        // Termo Especular (Blinn-Phong)
587	        vec3 h = normalize(v.xyz + l);
588	        float n_dot_h = max(0.0, dot(n.xyz, h));
589	        float shininess = mix(32.0, 64.0, metalness); 
590	        float specular_intensity = pow(n_dot_h, shininess);
591	
592	        // O metal pinta o reflexo com a cor da própria textura (Kd0)
593	        vec3 base_specular_color = mix(vec3(1.0), Kd0, metalness);
594	        
595	        // O metal brilha mais forte com as luzes
596	        float metal_boost = mix(1.0, 3.0, metalness);
597	
598	        float current_ks = Ks_map;
599	        // Se for uma peça do rádio e não tiver Ks_map definido, damos um brilho base de 0.3
600	        if (object_id >= RADIO_SHELL && object_id <= RADIO_BASE_PART && Ks_map == 0.0) {
601	            current_ks = 0.3; 
602	        }
603	
604	        vec3 specular = base_specular_color * LIGHT_COLORS[i] * specular_intensity * current_ks * metal_boost;
605	
606	        // vec3 specular = vec3(1.0) * LIGHT_COLORS[i] * specular_intensity * Ks_map; // Antigo
607	
608	        // Somamos a contribuição dessa luz com a atenuação aplicada
609	        total_diffuse += diffuse * attenuation;
610	        total_specular += specular * attenuation;
611	    }
612	
613	    // Luz ambiente bem fraca (para as sombras não ficarem 100% pretas)
614	    // A original, para comparação também, era 0.05, mas foi diminuída para criar um ambiente levemente mais escuro/dependente das luzes
615	    vec3 ambient_light = Kd0 * 0.01;
616	
617	    // Consideramos a lanterna do jogador, se ligada
618	    vec3 flashlight_color = vec3(0.85, 0.95, 1.0); // Cor levemente amarelada
619	    vec3 final_flashlight = vec3(0.0);
620	
621	    if (flashlight_on == 1) {
622	        vec3 L_spot = normalize(flashlight_pos.xyz - p.xyz);
623	        vec3 D_spot = normalize(flashlight_dir.xyz);
624	        
625	        // Cálculo do ângulo do cone (o dot product compara a luz com o centro do cone)
626	        float cos_theta = dot(-L_spot, D_spot);
627	        float cos_cutoff = cos(radians(25.0)); // 25 graus de abertura
628	        
629	        if (cos_theta > cos_cutoff) {
630	            // Atenuação por distância (para não iluminar o mundo todo)
631	            float dist = length(flashlight_pos.xyz - p.xyz);
632	            float attenuation = 1.0 / (1.0 + 0.1 * dist + 0.01 * (dist * dist));
633	            
634	            // Intensidade baseada no ângulo (suaviza as bordas do cone)
635	            float epsilon = 0.05;
636	            float spot_intensity = smoothstep(cos_cutoff, cos_cutoff + epsilon, cos_theta);
637	            
638	            final_flashlight = Kd0 * flashlight_color * attenuation * spot_intensity;
639	        }
640	    }
641	
642	    //  Cor final do fragmento somada com a luz da lanterna no final
643	    color.rgb = ambient_light + total_diffuse + total_specular + final_flashlight + emissive_color;
644	
645	    // NOTE: Se você quiser fazer o rendering de objetos transparentes, é
646	    // necessário:
647	    // 1) Habilitar a operação de "blending" de OpenGL logo antes de realizar o
648	    //    desenho dos objetos transparentes, com os comandos abaixo no código C++:
649	    //      glEnable(GL_BLEND);
650	    //      glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA);
651	    // 2) Realizar o desenho de todos objetos transparentes *após* ter desenhado
652	    //    todos os objetos opacos; e
653	    // 3) Realizar o desenho de objetos transparentes ordenados de acordo com
654	    //    suas distâncias para a câmera (desenhando primeiro objetos
655	    //    transparentes que estão mais longe da câmera).
656	    // Alpha default = 1 = 100% opaco = 0% transparente
657	    color.a = 1;
658	
659	    if (object_id == GLASS)
660	    {
661	        color.a = 0.5;
662	    }
663	
664	    // Cor final com correção gamma, considerando monitor sRGB.
665	    // Veja https://en.wikipedia.org/w/index.php?title=Gamma_correction&oldid=751281772#Windows.2C_Mac.2C_sRGB_and_TV.2Fvideo_standard_gammas
666	    color.rgb = pow(color.rgb, vec3(1.0,1.0,1.0)/2.2);
667	} 
